 84→pm_install() {
 85→    local package=$(pm_map_package_name "$1")
 86→    [[ -z "$package" ]] && return 1
 87→
 88→    # Route BINARY_INSTALL: prefixed packages to the binary installer
 89→    if [[ "$package" == BINARY_INSTALL:* ]]; then
 90→        local binary_name="${package#BINARY_INSTALL:}"
 91→        if declare -f install_binary >/dev/null 2>&1; then
 92→            install_binary "$binary_name"
 93→            return $?
 94→        else
 95→            log_verbose "Binary installer not available for $binary_name"
 96→            return 1
 97→        fi
 98→    fi
 99→
100→    if [[ "${DRY_RUN:-false}" == "true" ]]; then
101→        print_warning "DRY RUN: Would install $package via $LINUX_PM"
102→        return 0
103→    fi
104→    if [[ "${HAS_SUDO:-false}" != "true" ]]; then
105→        print_warning "Cannot install $package (no sudo)"
106→        return 1
107→    fi
108→
109→    case "$LINUX_PM" in
110→    apt)
111→        sudo apt-get install -y "$package" 2>&1 | grep -v "is already the newest version" || return 0
112→        ;;
113→    yum | dnf)
114→        sudo $LINUX_PM install -y "$package"
115→        ;;
116→    pacman)
117→        sudo pacman -S --noconfirm "$package"
118→        ;;
119→    esac
120→}
