122→pm_install_batch() {
123→    local packages=("$@")
124→    local mapped=()
125→    local binary_installs=()
126→
127→    for pkg in "${packages[@]}"; do
128→        local m=$(pm_map_package_name "$pkg")
129→        if [[ -z "$m" ]]; then
130→            continue
131→        elif [[ "$m" == BINARY_INSTALL:* ]]; then
132→            binary_installs+=("${m#BINARY_INSTALL:}")
133→        else
134→            mapped+=("$m")
135→        fi
136→    done
137→
138→    # Install binary packages individually
139→    for bin_pkg in "${binary_installs[@]}"; do
140→        if declare -f install_binary >/dev/null 2>&1; then
141→            install_binary "$bin_pkg" || log_verbose "Binary install failed for $bin_pkg"
142→        fi
143→    done
144→
145→    # Install system packages in batch
146→    [[ ${#mapped[@]} -eq 0 ]] && return 0
147→
148→    if [[ "${DRY_RUN:-false}" == "true" ]]; then
149→        print_warning "DRY RUN: Would install batch via $LINUX_PM: ${mapped[*]}"
150→        return 0
151→    fi
152→    [[ "${HAS_SUDO:-false}" != "true" ]] && return 1
153→
154→    case "$LINUX_PM" in
155→    apt)
156→        sudo apt-get install -y "${mapped[@]}"
157→        ;;
158→    yum | dnf)
159→        sudo $LINUX_PM install -y "${mapped[@]}"
160→        ;;
161→    pacman)
162→        sudo pacman -S --noconfirm "${mapped[@]}"
163→        ;;
164→    esac
165→}
