169→
170→    # BINARY_INSTALL: packages — check if command exists
171→    if [[ "$package" == BINARY_INSTALL:* ]]; then
172→        command -v "${package#BINARY_INSTALL:}" &>/dev/null
173→        return $?
174→    fi
175→
176→    case "$LINUX_PM" in
